package com.google.gson;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.lang.reflect.Field;
import java.util.ArrayList;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonArrayTest {

  private JsonArray jsonArray;
  private ArrayList<JsonElement> mockElements;

  @BeforeEach
  public void setUp() throws Exception {
    jsonArray = new JsonArray();

    // Create a mock ArrayList<JsonElement>
    mockElements = mock(ArrayList.class);

    // Use reflection to set the private final field 'elements' to the mock
    Field elementsField = JsonArray.class.getDeclaredField("elements");
    elementsField.setAccessible(true);
    elementsField.set(jsonArray, mockElements);
  }

  @Test
  public void testHashCode_returnsElementsHashCode() {
    int expectedHashCode = 123456789;
    when(mockElements.hashCode()).thenReturn(expectedHashCode);

    int actualHashCode = jsonArray.hashCode();

    assertEquals(expectedHashCode, actualHashCode);
  }

  @Test
  public void testHashCode_withRealElements() throws Exception {
    // Replace mock with a real ArrayList with some JsonElements
    ArrayList<JsonElement> realElements = new ArrayList<>();
    Field elementsField = JsonArray.class.getDeclaredField("elements");
    elementsField.setAccessible(true);
    elementsField.set(jsonArray, realElements);

    JsonElement element1 = mock(JsonElement.class);
    JsonElement element2 = mock(JsonElement.class);

    realElements.add(element1);
    realElements.add(element2);

    int expectedHashCode = realElements.hashCode();
    int actualHashCode = jsonArray.hashCode();

    assertEquals(expectedHashCode, actualHashCode);
  }
}
